import{_ as e,c as t,o as s,a1 as l}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Быстрый старт: Использование Agent Skills | opencode-agent-skills","description":"Узнайте, как быстро начать работу с плагином OpenCode Agent Skills. Установите и настройте плагин, создайте первый навык и освойте основные функции за 30 минут.","frontmatter":{"title":"Быстрый старт: Использование Agent Skills | opencode-agent-skills","sidebarTitle":"Начало за 30 минут","order":1,"subtitle":"Быстрый старт","description":"Узнайте, как быстро начать работу с плагином OpenCode Agent Skills. Установите и настройте плагин, создайте первый навык и освойте основные функции за 30 минут."},"headers":[],"relativePath":"ru/joshuadavidthomas/opencode-agent-skills/start/index.md","filePath":"ru/joshuadavidthomas/opencode-agent-skills/start/index.md"}'),o={name:"ru/joshuadavidthomas/opencode-agent-skills/start/index.md"};function i(r,a,n,d,c,h){return s(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="быстрыи-старт" tabindex="-1">Быстрый старт <a class="header-anchor" href="#быстрыи-старт" aria-label="Permalink to &quot;Быстрый старт&quot;">​</a></h1><p>Этот раздел поможет вам начать работу с плагином OpenCode Agent Skills с нуля. Вы узнаете о ключевых преимуществах плагина, выполните установку и настройку, а также создадите свой первый навык.</p><h2 id="содержание-раздела" tabindex="-1">Содержание раздела <a class="header-anchor" href="#содержание-раздела" aria-label="Permalink to &quot;Содержание раздела&quot;">​</a></h2><div class="grid-cards"><a href="./what-is-opencode-agent-skills/" class="card"><h3>Что такое OpenCode Agent Skills?</h3><p>Узнайте о ключевых преимуществах и функциях плагина, включая динамическое обнаружение навыков, внедрение контекста, сжатие и восстановление.</p></a><a href="./installation/" class="card"><h3>Руководство по установке</h3><p>Выполните установку плагина и проверьте его работу. Поддерживаются три способа: базовая установка, установка фиксированной версии и локальная установка для разработки.</p></a><a href="./creating-your-first-skill/" class="card"><h3>Создайте свой первый навык</h3><p>Освойте структуру директорий навыков и формат SKILL.md, создайте и протестируйте простой навык.</p></a></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Рекомендуется изучать материалы в следующем порядке:</p><ol><li><strong><a href="./what-is-opencode-agent-skills/">Что такое OpenCode Agent Skills?</a></strong> — Сначала узнайте, что может делать плагин, чтобы сформировать общее представление</li><li><strong><a href="./installation/">Руководство по установке</a></strong> — Установите плагин, чтобы OpenCode мог управлять навыками</li><li><strong><a href="./creating-your-first-skill/">Создайте свой первый навык</a></strong> — Приступайте к практике и создайте свой первый навык</li></ol><div class="tip custom-block"><p class="custom-block-title">Примерное время</p><p>На изучение этого раздела потребуется примерно 30-45 минут.</p></div><h2 id="следующии-шаг" tabindex="-1">Следующий шаг <a class="header-anchor" href="#следующии-шаг" aria-label="Permalink to &quot;Следующий шаг&quot;">​</a></h2><p>После завершения этого раздела вы можете продолжить изучение <strong><a href="./../platforms/">Функций платформы</a></strong>, чтобы глубже понять механизмы обнаружения навыков, загрузки навыков, автоматического сопоставления и другие расширенные функции.</p>',10)])])}const k=e(o,[["render",i]]);export{g as __pageData,k as default};
